            for (int j = i - 1; j >= 0; j--) {
                if (templeHeight[j] < templeHeight[j + 1]) {
                    left++;
                } else {
                    break;
                }
            }
            for (int j = i + 1; j < n; j++) {
                if (templeHeight[j] < templeHeight[j - 1]) {
                    right++;
                } else {
                    break;
                }
            }
            sum += Math.max(right, left) + 1;
        }
        return sum;
    }

